// // This module generates a Johnson sequence on the negative edge of the clock signal.
module johnson_counter(clk, rst, q);

    input  clk;
    input  rst;
    output reg [3:0] q;

    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 4'b0000;
        else
            q <= {~q[0], q[3:1]};
    end

endmodule
